"use client";

import { useRef } from "react";
import Link from "next/link";
import Image from "next/image";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { useGSAP } from "@gsap/react";
import { HeartPulse, Palmtree, Utensils, Clock, HeartHandshake, ShieldCheck, MapPin } from "lucide-react";

gsap.registerPlugin(ScrollTrigger, useGSAP);

export default function Home() {
  const containerRef = useRef<HTMLDivElement>(null);
  const heroRef = useRef<HTMLDivElement>(null);
  const servicesRef = useRef<HTMLDivElement>(null);
  const philRef = useRef<HTMLDivElement>(null);
  const q1Ref = useRef<HTMLParagraphElement>(null);
  const q2Ref = useRef<HTMLParagraphElement>(null);

  useGSAP(() => {
    // Hero text reveal
    gsap.from(".hero-text", {
      y: 40,
      opacity: 0,
      duration: 1.2,
      stagger: 0.15,
      ease: "power3.out",
      delay: 0.5,
    });

    // Philosophy ScrollTrigger
    gsap.from(q1Ref.current, {
      scrollTrigger: {
        trigger: philRef.current,
        start: "top 70%",
      },
      y: 30,
      opacity: 0,
      duration: 1,
      ease: "power3.out",
    });

    gsap.from(q2Ref.current, {
      scrollTrigger: {
        trigger: philRef.current,
        start: "top 50%",
      },
      y: 30,
      opacity: 0,
      duration: 1.2,
      ease: "power3.out",
      delay: 0.2,
    });

    // Services staggered reveal
    gsap.from(".service-card", {
      scrollTrigger: {
        trigger: servicesRef.current,
        start: "top 75%",
      },
      y: 40,
      opacity: 0,
      duration: 1,
      stagger: 0.15,
      ease: "power3.out",
    });

  }, { scope: containerRef });

  return (
    <div ref={containerRef} className="flex flex-col w-full min-h-screen">
      {/* Hero Section */}
      <section ref={heroRef} className="relative w-full h-[100dvh] min-h-[600px] flex items-end pb-24 md:pb-32 px-6 md:px-12 overflow-hidden bg-charcoal">
        <img
          src="https://images.unsplash.com/photo-1576765974102-b756026ecee3?q=80&w=2938&auto=format&fit=crop"
          alt="Ambiente acolhedor e familiar"
          className="absolute inset-0 w-full h-full object-cover object-center opacity-70 scale-105"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-charcoal/90 via-charcoal/40 to-transparent pointer-events-none" />

        <div className="relative z-10 w-full max-w-6xl mx-auto flex flex-col gap-6">
          <h1 className="hero-text font-serif text-5xl md:text-7xl lg:text-8xl text-cream max-w-4xl leading-[1.1]">
            Onde a dignidade encontra uma nova <span className="italic">fam├¡lia</span>
          </h1>
          <p className="hero-text font-sans text-xl md:text-2xl text-rose font-medium mt-2">
            L├¡der na arte de cuidar.
          </p>
          <div className="hero-text mt-6">
            <Link
              href="/contacto"
              className="inline-flex items-center justify-center bg-rose text-cream font-sans font-medium px-8 py-3.5 rounded-[1.5rem] overflow-hidden group hover:scale-[1.03] transition-transform duration-300 ease-[cubic-bezier(0.25,0.46,0.45,0.94)] relative"
            >
              <span className="relative z-10">Marcar Visita</span>
              <div className="absolute inset-0 bg-stone scale-y-0 origin-bottom group-hover:scale-y-100 transition-transform duration-500 ease-[cubic-bezier(0.25,0.46,0.45,0.94)] z-0" />
            </Link>
          </div>
        </div>
      </section>

      {/* Services Highlight Strip */}
      <section ref={servicesRef} className="relative w-full px-6 md:px-12 py-24 md:py-32 bg-cream flex justify-center">
        <div className="w-full max-w-6xl grid grid-cols-1 md:grid-cols-3 gap-8">
          {[
            { icon: HeartPulse, title: "Cuidados M├®dicos", desc: "Acompanhamento cl├¡nico e enfermagem dispon├¡vel 24 horas por dia." },
            { icon: Palmtree, title: "Atividades e Bem-Estar", desc: "Programas di├írios de estimula├º├úo cognitiva, f├¡sica e social." },
            { icon: Utensils, title: "Nutri├º├úo e Alimenta├º├úo", desc: "Planos alimentares personalizados e confecionados localmente com rigor." }
          ].map((srv, i) => (
            <div key={i} className="service-card h-full">
              <Link
                href="/servicos"
                className="group w-full h-full bg-stone/5 p-8 rounded-[2rem] border border-stone/10 hover:border-stone/30 hover:bg-stone/10 hover:-translate-y-2 transition-all duration-500 ease-[cubic-bezier(0.25,0.46,0.45,0.94)] flex flex-col gap-6 cursor-pointer"
              >
                <div className="w-14 h-14 shrink-0 rounded-full bg-cream flex items-center justify-center text-sage group-hover:text-rose transition-colors duration-300 shadow-sm border border-stone/10">
                  <srv.icon className="w-6 h-6" />
                </div>
                <div>
                  <h3 className="font-serif text-2xl text-charcoal mb-3">{srv.title}</h3>
                  <p className="font-sans text-charcoal/70 leading-relaxed text-sm md:text-base">{srv.desc}</p>
                </div>
              </Link>
            </div>
          ))}
        </div>
      </section>

      {/* Trust Strip */}
      <section className="relative w-full px-6 py-12 bg-stone flex justify-center border-y border-stone/20 overflow-hidden">
        <div className="w-full max-w-6xl flex flex-wrap justify-center gap-8 md:gap-16">
          {[
            { icon: Clock, label: "Atendimento 24h" },
            { icon: HeartHandshake, label: "Ambiente Familiar" },
            { icon: ShieldCheck, label: "Equipa Especializada" },
            { icon: MapPin, label: "Localiza├º├úo em Roli├ºa" }
          ].map((trust, i) => (
            <div key={i} className="flex items-center gap-3 text-cream/90">
              <trust.icon className="w-5 h-5 text-cream/70" />
              <span className="font-sans font-medium tracking-wide text-sm">{trust.label}</span>
            </div>
          ))}
        </div>
      </section>

      {/* Philosophy / Manifesto Section */}
      <section ref={philRef} className="relative w-full py-32 md:py-48 px-6 md:px-12 bg-charcoal overflow-hidden flex items-center justify-center">
        <div className="absolute inset-0 opacity-20 mix-blend-overlay pointer-events-none">
          <img
            src="https://images.unsplash.com/photo-1476610182048-b716b8518aae?auto=format&fit=crop&q=80&w=2600"
            alt="Textura de fundo"
            className="absolute inset-0 w-full h-full object-cover object-center grayscale"
          />
        </div>

        <div className="relative z-10 w-full max-w-5xl mx-auto flex flex-col gap-12 md:gap-16">
          <p ref={q1Ref} className="font-serif text-2xl md:text-3xl lg:text-4xl text-cream/60 max-w-2xl">
            &quot;A maioria v├¬ o envelhecimento como um desafio a gerir.&quot;
          </p>
          <p ref={q2Ref} className="font-serif text-4xl md:text-5xl lg:text-7xl text-cream leading-[1.15] lg:leading-[1.1] ml-auto text-right max-w-4xl">
            &quot;N├│s vemos cada hist├│ria de vida como uma <span className="text-rose italic">arte</span> a honrar.&quot;
          </p>
        </div>
      </section>

      {/* CTA Banner */}
      <section className="relative w-full py-24 md:py-32 px-6 md:px-12 bg-cream flex justify-center text-center">
        <div className="w-full max-w-3xl flex flex-col items-center gap-10 bg-stone p-10 md:p-16 rounded-[2.5rem] shadow-xl relative overflow-hidden group">
          <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1516086745152-19e49c7161b0?q=80&w=2670&auto=format&fit=crop')] opacity-10 bg-cover bg-center mix-blend-overlay transition-transform duration-1000 group-hover:scale-105" />

          <div className="relative z-10 flex flex-col items-center gap-4">
            <h2 className="font-serif text-4xl md:text-5xl text-cream">Venha conhecer a nossa casa</h2>
            <p className="font-sans text-cream/80 max-w-lg mb-4">
              Estamos dispon├¡veis para o receber e mostrar-lhe o ambiente familiar que nos distingue.
            </p>
            <div className="flex flex-col md:flex-row gap-4 md:gap-8 items-center font-mono text-sm tracking-tight text-cream/90 mb-4">
              <a href="tel:913844028" className="hover:text-rose transition-colors">913 844 028</a>
              <span className="hidden md:block opacity-30">|</span>
              <a href="tel:918299532" className="hover:text-rose transition-colors">918 299 532</a>
              <span className="hidden md:block opacity-30">|</span>
              <a href="tel:913787535" className="hover:text-rose transition-colors">913 787 535</a>
            </div>

            <Link
              href="/contacto"
              className="inline-flex items-center justify-center bg-cream text-charcoal font-sans font-medium px-8 py-3.5 rounded-[1.5rem] overflow-hidden group/btn hover:scale-[1.03] transition-transform duration-300 ease-[cubic-bezier(0.25,0.46,0.45,0.94)] relative mt-2"
            >
              <span className="relative z-10 group-hover/btn:text-cream transition-colors duration-300">Enviar Mensagem</span>
              <div className="absolute inset-0 bg-rose scale-y-0 origin-bottom group-hover/btn:scale-y-100 transition-transform duration-500 ease-[cubic-bezier(0.25,0.46,0.45,0.94)] z-0" />
            </Link>

            <p className="font-mono text-xs text-cream/50 mt-6 tracking-widest uppercase">
              Hor├írio de Visitas: 10hÔÇô19h
            </p>
          </div>
        </div>
      </section>

    </div>
  );
}

"use client";

import { useEffect, useRef } from "react";
import Image from "next/image";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { Heart, Home as HomeIcon, Star, Sun } from "lucide-react";

gsap.registerPlugin(ScrollTrigger);

const timeline = [
    { year: "2010", title: "O In├¡cio do Sonho", desc: "Abertura das portas com a vis├úo de criar um lar que fosse verdadeiramente uma extens├úo da fam├¡lia." },
    { year: "2015", title: "Expans├úo dos Cuidados", desc: "Integra├º├úo de equipa m├®dica 24h e moderniza├º├úo das instala├º├Áes para maior conforto." },
    { year: "2020", title: "Reconhecimento de Excel├¬ncia", desc: "Distinguido pelas pr├íticas humanizadas no cuidado s├®nior na regi├úo Oeste." },
    { year: "2024", title: "Renova├º├úo e Futuro", desc: "Atualiza├º├úo de todos os espa├ºos de bem-estar com foco na sustentabilidade e terapias avan├ºadas." }
];

const values = [
    { icon: Heart, title: "Dignidade", desc: "Tratamos cada residente com o respeito e rever├¬ncia que a sua hist├│ria de vida merece." },
    { icon: HomeIcon, title: "Fam├¡lia", desc: "Cultivamos um ambiente acolhedor onde os afetos s├úo t├úo importantes quanto a sa├║de." },
    { icon: Star, title: "Profissionalismo", desc: "O nosso rigor cl├¡nico garante seguran├ºa, confian├ºa e paz de esp├¡rito em todos os momentos." },
    { icon: Sun, title: "Esperan├ºa", desc: "Acreditamos que cada dia ├® uma oportunidade para sorrir, aprender e partilhar." }
];

const team = [
    { name: "Dra. Maria Helena", role: "Diretora T├®cnica", img: "https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?q=80&w=2788&auto=format&fit=crop" },
    { name: "Enf. Jo├úo Silva", role: "Enfermeiro Chefe", img: "https://images.unsplash.com/photo-1612349317150-e413f6a5b16d?q=80&w=2670&auto=format&fit=crop" },
    { name: "Sofia Mendes", role: "Animadora Sociocultural", img: "https://images.unsplash.com/photo-1580489944761-15a19d654956?q=80&w=2661&auto=format&fit=crop" },
    { name: "Rita Costa", role: "Nutricionista Cl├¡nica", img: "https://images.unsplash.com/photo-1559839734-2b71ea197ec2?auto=format&fit=crop&q=80&w=800" }
];

export default function Sobre() {
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const ctx = gsap.context(() => {
            gsap.from(".hero-text", {
                y: 40,
                opacity: 0,
                duration: 1.2,
                stagger: 0.15,
                ease: "power3.out",
            });

            gsap.utils.toArray<HTMLElement>(".timeline-item").forEach((item) => {
                gsap.from(item, {
                    scrollTrigger: {
                        trigger: item,
                        start: "top 80%",
                    },
                    y: 30,
                    opacity: 0,
                    duration: 1,
                    ease: "power3.out",
                });
            });

            gsap.from(".value-card", {
                scrollTrigger: {
                    trigger: ".values-grid",
                    start: "top 75%",
                },
                y: 30,
                opacity: 0,
                duration: 0.8,
                stagger: 0.1,
                ease: "power2.out",
            });

            gsap.from(".team-member", {
                scrollTrigger: {
                    trigger: ".team-grid",
                    start: "top 80%",
                },
                y: 40,
                opacity: 0,
                duration: 1,
                stagger: 0.15,
                ease: "power3.out",
            });

        }, containerRef);
        return () => ctx.revert();
    }, []);

    return (
        <div ref={containerRef} className="flex flex-col w-full min-h-screen">

            {/* Mission Hero */}
            <section className="relative w-full py-32 md:py-48 px-6 md:px-12 bg-cream flex justify-center">
                <div className="w-full max-w-4xl flex flex-col items-center text-center gap-8">
                    <h1 className="hero-text font-serif text-5xl md:text-7xl text-charcoal leading-tight">
                        A nossa miss├úo ├® <span className="text-rose italic">cuidar</span> de quem sempre cuidou de n├│s.
                    </h1>
                    <p className="hero-text font-sans text-lg md:text-xl text-charcoal/70 max-w-2xl leading-relaxed">
                        No Lar Familiar Nossa Senhora da Esperan├ºa, acreditamos que envelhecer com dignidade exige mais do que excel├¬ncia cl├¡nica ÔÇö exige um ambiente familiar, afeto genu├¡no e um profundo respeito por cada hist├│ria de vida.
                    </p>
                </div>
            </section>

            {/* Timeline Section */}
            <section className="relative w-full py-24 md:py-32 px-6 md:px-12 bg-stone/5 flex justify-center">
                <div className="w-full max-w-4xl flex flex-col">
                    <h2 className="font-serif text-4xl text-charcoal mb-16 text-center">A Nossa Hist├│ria</h2>

                    <div className="relative flex flex-col gap-12 md:gap-0">
                        {/* Center line for desktop */}
                        <div className="hidden md:block absolute left-1/2 top-0 bottom-0 w-px bg-stone/20 -translate-x-1/2" />

                        {timeline.map((item, i) => (
                            <div key={i} className={`timeline-item relative flex flex-col md:flex-row items-center justify-between w-full ${i % 2 === 0 ? "md:flex-row-reverse" : ""}`}>

                                {/* Dot */}
                                <div className="hidden md:flex absolute left-1/2 -translate-x-1/2 w-4 h-4 bg-rose rounded-full z-10 shadow-[0_0_0_8px_rgba(245,240,232,1)]" />

                                {/* Desktop Empty Space */}
                                <div className="hidden md:block w-5/12" />

                                {/* Content */}
                                <div className="w-full md:w-5/12 bg-white/50 backdrop-blur-sm p-8 rounded-[2rem] border border-stone/10 md:my-8 shadow-sm">
                                    <span className="font-mono text-rose text-sm font-medium tracking-widest">{item.year}</span>
                                    <h3 className="font-serif text-2xl text-charcoal mt-2 mb-4">{item.title}</h3>
                                    <p className="font-sans text-charcoal/70 text-sm leading-relaxed">{item.desc}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* Values Grid */}
            <section className="relative w-full py-24 md:py-32 px-6 md:px-12 bg-cream flex justify-center">
                <div className="w-full max-w-6xl flex flex-col items-center">
                    <h2 className="font-serif text-4xl text-charcoal mb-16 text-center">Os Nossos Valores</h2>

                    <div className="values-grid grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 w-full">
                        {values.map((v, i) => (
                            <div key={i} className="value-card bg-stone p-8 rounded-[2rem] text-cream flex flex-col gap-6">
                                <div className="w-12 h-12 rounded-full bg-cream/10 flex items-center justify-center">
                                    <v.icon className="w-5 h-5 text-cream" />
                                </div>
                                <div>
                                    <h3 className="font-serif text-2xl mb-3">{v.title}</h3>
                                    <p className="font-sans text-cream/70 text-sm leading-relaxed">{v.desc}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* Team Section */}
            <section className="relative w-full py-24 md:py-32 px-6 md:px-12 bg-stone/5 flex justify-center">
                <div className="w-full max-w-6xl flex flex-col items-center">
                    <h2 className="font-serif text-4xl text-charcoal mb-4 text-center">A Nossa Equipa</h2>
                    <p className="font-sans text-charcoal/60 text-center max-w-2xl mb-16">
                        Profissionais dedicados, movidos pela voca├º├úo de cuidar e garantir o bem-estar absoluto de todos os nossos residentes.
                    </p>

                    <div className="team-grid grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 w-full">
                        {team.map((member, i) => (
                            <div key={i} className="team-member group relative w-full aspect-[3/4] rounded-[2rem] overflow-hidden bg-stone/10 isolate">
                                <img
                                    src={member.img}
                                    alt={member.name}
                                    className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                                />
                                {/* Gradient overlay */}
                                <div className="absolute inset-0 bg-gradient-to-t from-charcoal/80 via-charcoal/20 to-transparent z-10" />

                                {/* Content info */}
                                <div className="absolute bottom-0 left-0 w-full p-6 z-20 flex flex-col justify-end translate-y-2 group-hover:translate-y-0 transition-transform duration-500">
                                    <h3 className="font-serif text-2xl text-cream">{member.name}</h3>
                                    <p className="font-sans text-rose text-sm font-medium mt-1">{member.role}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

        </div>
    );
}

"use client";

import { useEffect, useState, useRef } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import gsap from "gsap";

const navLinks = [
    { name: "In├¡cio", path: "/" },
    { name: "Sobre N├│s", path: "/sobre" },
    { name: "Servi├ºos", path: "/servicos" },
    { name: "Contacto", path: "/contacto" },
];

export default function Navbar() {
    const [isScrolled, setIsScrolled] = useState(false);
    const [isMounted, setIsMounted] = useState(false);
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const pathname = usePathname();

    useEffect(() => {
        setIsMounted(true);
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 20);
        };
        window.addEventListener("scroll", handleScroll);
        return () => window.removeEventListener("scroll", handleScroll);
    }, []);

    // Close mobile menu on route change
    useEffect(() => {
        setIsMobileMenuOpen(false);
    }, [pathname]);

    return (
        <div className={`fixed top-8 left-0 w-full z-50 flex justify-center px-4 md:px-8 pointer-events-none transition-all duration-1000 ease-[cubic-bezier(0.25,0.46,0.45,0.94)] ${isMounted ? "translate-y-0 opacity-100" : "-translate-y-12 opacity-0"}`}>
            <nav
                className={`pointer-events-auto flex flex-col w-full max-w-6xl transition-all duration-500 overflow-hidden relative ${isScrolled || isMobileMenuOpen
                    ? "bg-cream/95 backdrop-blur-2xl border border-stone/20 shadow-xl shadow-charcoal/5"
                    : "bg-transparent border-transparent"
                    } rounded-[2rem] md:rounded-full`}
            >
                <div className="flex items-center justify-between w-full px-6 lg:px-8 py-3.5">
                    <div className="w-auto md:w-1/3 flex justify-start items-center">
                        <Link href="/" className="group flex flex-col shrink-0">
                            <span className={`font-serif text-xl sm:text-2xl font-medium tracking-wide transition-colors duration-300 drop-shadow-sm group-hover:-translate-y-[1px] ${!isScrolled && pathname === '/' && !isMobileMenuOpen ? "text-cream" : "text-charcoal"}`}>
                                Nossa Senhora da Esperan├ºa
                            </span>
                        </Link>
                    </div>

                    <div className="w-1/3 hidden md:flex items-center justify-center gap-6 lg:gap-8">
                        {navLinks.map((link) => {
                            const isActive = pathname === link.path;
                            const isHomeTop = !isScrolled && pathname === '/' && !isMobileMenuOpen;
                            return (
                                <Link
                                    key={link.path}
                                    href={link.path}
                                    className={`text-sm font-sans font-medium hover:-translate-y-[1px] transition-all duration-300 ${isActive ? "text-rose" : (isHomeTop ? "text-cream/90 hover:text-cream drop-shadow-md" : "text-charcoal/80 hover:text-charcoal")}`}
                                >
                                    {link.name}
                                </Link>
                            );
                        })}
                    </div>

                    <div className="w-auto md:w-1/3 flex justify-end items-center gap-4">
                        <Link
                            href="/contacto"
                            className={`hidden md:inline-flex items-center justify-center font-sans font-medium text-sm px-6 py-2.5 lg:px-8 lg:py-3 rounded-full overflow-hidden group hover:scale-[1.03] transition-transform duration-300 ease-[cubic-bezier(0.25,0.46,0.45,0.94)] relative ${(!isScrolled && pathname === '/' && !isMobileMenuOpen) ? 'bg-cream text-charcoal' : 'bg-rose text-cream'}`}
                        >
                            <span className="relative z-10 transition-colors duration-300">Marcar Visita</span>
                            <div className={`absolute inset-0 scale-y-0 origin-bottom group-hover:scale-y-100 transition-transform duration-500 ease-[cubic-bezier(0.25,0.46,0.45,0.94)] z-0 ${(!isScrolled && pathname === '/' && !isMobileMenuOpen) ? 'bg-rose' : 'bg-stone'}`} />
                        </Link>

                        <button
                            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                            className={`md:hidden flex flex-col justify-center items-center w-10 h-10 rounded-full shrink-0 transition-colors duration-300 ${(!isScrolled && pathname === '/' && !isMobileMenuOpen) ? 'bg-cream/20 text-cream hover:bg-cream/30' : 'bg-stone/10 text-charcoal hover:bg-stone/20'}`}
                        >
                            <span className={`block w-5 h-0.5 bg-current transition-all duration-300 ${isMobileMenuOpen ? 'rotate-45 translate-y-[1.5px]' : 'mb-1'}`}></span>
                            <span className={`block w-5 h-0.5 bg-current transition-all duration-300 ${isMobileMenuOpen ? 'opacity-0' : 'mb-1'}`}></span>
                            <span className={`block w-5 h-0.5 bg-current transition-all duration-300 ${isMobileMenuOpen ? '-rotate-45 -translate-y-[1.5px]' : ''}`}></span>
                        </button>
                    </div>
                </div>

                {/* Mobile Dropdown Menu */}
                <div className={`md:hidden flex flex-col items-center justify-center gap-6 transition-all duration-500 ease-[cubic-bezier(0.25,0.46,0.45,0.94)] ${isMobileMenuOpen ? 'max-h-[400px] opacity-100 pb-8 pt-4' : 'max-h-0 opacity-0 py-0'}`}>
                    {navLinks.map((link) => {
                        const isActive = pathname === link.path;
                        return (
                            <Link
                                key={link.path}
                                href={link.path}
                                className={`text-lg font-serif font-medium transition-colors duration-300 ${isActive ? "text-rose" : "text-charcoal/80 hover:text-charcoal"}`}
                            >
                                {link.name}
                            </Link>
                        );
                    })}
                    <Link
                        href="/contacto"
                        className="mt-4 inline-flex items-center justify-center bg-rose text-cream font-sans font-medium text-sm px-8 py-3 rounded-full overflow-hidden group hover:scale-[1.03] transition-transform duration-300 relative"
                    >
                        <span className="relative z-10">Marcar Visita</span>
                        <div className="absolute inset-0 bg-stone scale-y-0 origin-bottom group-hover:scale-y-100 transition-transform duration-500 z-0" />
                    </Link>
                </div>
            </nav>
        </div>
    );
}
